//! Corridor build/update from declared bindings. A `Binding` pins a
//! queue name + matching key; the kind of match (direct, topic, headers)
//! is encoded in the `BindingKey` discriminator. Bindings are stored
//! inside each exchange in the broker's exchange table — this module
//! just holds the match predicates.

use std::collections::HashMap;

/// A binding from an exchange to a queue.
#[derive(Clone, Debug)]
pub struct Binding {
    /// Target queue (== consumer name).
    pub queue: String,
    /// Match predicate.
    pub key: BindingKey,
}

/// The match predicate paired with a binding.
#[derive(Clone, Debug)]
pub enum BindingKey {
    /// Exact match (direct exchange).
    Direct(String),
    /// Topic-style pattern with `*` (one word) and `#` (zero+ words).
    Topic(String),
    /// Headers all-of match (headers exchange).
    Headers(HashMap<String, String>),
}

impl BindingKey {
    /// True if this key matches `routing_key` as a *direct* binding.
    /// `Topic` and `Headers` keys never match on direct exchanges.
    pub fn matches_direct(&self, routing_key: &str) -> bool {
        match self {
            BindingKey::Direct(k) => k == routing_key,
            _ => false,
        }
    }

    /// True if this key matches `routing_key` as a *topic* binding.
    /// `Direct(k)` is accepted as the literal topic `k` (an
    /// empty-pattern match) so callers can mix exact + wildcard bindings
    /// on the same topic exchange without juggling key variants.
    pub fn matches_topic(&self, routing_key: &str) -> bool {
        match self {
            BindingKey::Topic(pattern) => topic_match(pattern, routing_key),
            BindingKey::Direct(k) => topic_match(k, routing_key),
            _ => false,
        }
    }

    /// True if this key matches `headers` as a *headers* binding.
    /// All declared header k/v pairs must match the message's headers.
    pub fn matches_headers(&self, headers: &HashMap<String, String>) -> bool {
        match self {
            BindingKey::Headers(req) => req.iter().all(|(k, v)| headers.get(k) == Some(v)),
            _ => false,
        }
    }
}

/// AMQP topic matcher. Dotted segments; `*` matches exactly one
/// segment; `#` matches zero+ segments. Simple recursive impl — topic
/// patterns are short.
fn topic_match(pattern: &str, key: &str) -> bool {
    let pp: Vec<&str> = pattern.split('.').collect();
    let kk: Vec<&str> = key.split('.').collect();
    match_segments(&pp, &kk)
}

fn match_segments(p: &[&str], k: &[&str]) -> bool {
    match (p.first(), k.first()) {
        (None, None) => true,
        (None, Some(_)) => false,
        (Some(&"#"), _) => {
            // `#` matches 0+ segments. Try every suffix length of k.
            let rest_p = &p[1..];
            if match_segments(rest_p, k) {
                return true;
            }
            for i in 1..=k.len() {
                if match_segments(rest_p, &k[i..]) {
                    return true;
                }
            }
            false
        }
        (Some(_), None) => false,
        (Some(&"*"), Some(_)) => match_segments(&p[1..], &k[1..]),
        (Some(ps), Some(ks)) => ps == ks && match_segments(&p[1..], &k[1..]),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn direct_exact_match_only() {
        let k = BindingKey::Direct("compute".into());
        assert!(k.matches_direct("compute"));
        assert!(!k.matches_direct("compute.other"));
    }

    #[test]
    fn topic_star_matches_one_segment() {
        assert!(topic_match("logs.*.fatal", "logs.error.fatal"));
        assert!(!topic_match("logs.*.fatal", "logs.error.deep.fatal"));
    }

    #[test]
    fn topic_hash_matches_zero_or_more() {
        assert!(topic_match("logs.#", "logs"));
        assert!(topic_match("logs.#", "logs.error.fatal"));
        assert!(topic_match("#.fatal", "logs.error.fatal"));
        assert!(!topic_match("logs.#.fatal", "logs.error"));
        assert!(topic_match("logs.#.fatal", "logs.error.fatal"));
        assert!(topic_match("logs.#.fatal", "logs.fatal"));
    }

    #[test]
    fn headers_all_must_match() {
        let mut req = HashMap::new();
        req.insert("x-region".to_string(), "us-east".to_string());
        req.insert("x-tier".to_string(), "gold".to_string());
        let k = BindingKey::Headers(req);
        let mut msg = HashMap::new();
        msg.insert("x-region".to_string(), "us-east".to_string());
        msg.insert("x-tier".to_string(), "gold".to_string());
        msg.insert("x-extra".to_string(), "ok".to_string());
        assert!(k.matches_headers(&msg));
        msg.remove("x-tier");
        assert!(!k.matches_headers(&msg));
    }
}
